  // Créer une signature basée sur titre + entreprise + localisation
  const signature = `${normalize(job.title)}_${normalize(job.company)}_${normalize(job.location)}`;

  let isDuplicate = false;

  for (const [existingSignature, existingJob] of seenSignatures) {
    // Vérifier similarité du titre et de l'entreprise
    const titleSim = similarity(job.title, existingJob.title);
    const companySim = similarity(job.company, existingJob.company);

    if (titleSim > 0.8 && companySim > 0.8) {
      isDuplicate = true;
      console.log(`Doublon détecté: "${job.title}" (${job.source}) ~ "${existingJob.title}" (${existingJob.source})`);
      break;
    }
  }

  if (!isDuplicate) {
    seenSignatures.set(signature, job);
    uniqueJobs.push(job);
  }
}

