        <button class="filter-btn" onclick="filterJobs('freelance')">Freelance</button>
        ${Object.keys(jobsBySource).map(source => 
          `<button class="filter-btn" onclick="filterJobs('${source}')">${sourceNames[source]}</button>`
        ).join('')}
      </div>
    </div>

    ${allJobs.length > 0 ? `
      <div class="jobs-grid">
        ${jobCardsHtml}
      </div>
    ` : `
      <div class="no-results">
        <h2>😔 Aucune offre trouvée</h2>
        <p>Essayez de modifier vos critères de recherche ou d'élargir la zone géographique.</p>
      </div>
    `}

    <div class="footer">
      <p>Propulsé par <a href="https://jobnexai.com">JobNexAI</a> • Session: ${criteria.session_id}</p>
    </div>
  </div>

  <script>
    function filterJobs(filter) {
      const cards = document.querySelectorAll('.job-card');
      const buttons = document.querySelectorAll('.filter-btn');

      buttons.forEach(btn => btn.classList.remove('active'));
      event.target.classList.add('active');

      cards.forEach(card => {
        const source = card.dataset.source;
        let show = false;

        if (filter === 'all') {
          show = true;
        } else if (filter === 'cdi') {
          show = ['indeed', 'linkedin', 'wttj'].includes(source);
        } else if (filter === 'freelance') {
          show = ['malt', 'free-work'].includes(source);
        } else {
          show = source === filter;
        }

        card.style.display = show ? 'block' : 'none';
      });
    }
  </script>
</body>
</html>
`;

return {
  json: {
    html: html,
    session_id: criteria.session_id,
    total_jobs: allJobs.length,
    jobs_by_source: Object.fromEntries(
      Object.entries(jobsBySource).map(([k, v]) => [k, v.length])
    ),
    criteria: criteria
  }
};
